		allMoves.sort((a, b) => String(a).localeCompare(String(b)));
		renderMoves.sort((a, b) => a.localeCompare(b));

		const renderSet = new Set(renderMoves.map(name => name));
		const missingMoves = allMoves.filter(name => !renderSet.has(name));

